# Let me create a campaign classification based on this pattern

def identify_campaign(row):
    country = row['country']

    # Map countries to campaigns based on naming patterns
    if country == 'US':
        return 'Campaign_US_Short'
    elif country == 'United States':
        return 'Campaign_US_Long'
    elif country == 'UK':
        return 'Campaign_UK_Short'
    elif country == 'United Kingdom':
        return 'Campaign_UK_Long'
    elif country == 'India':
        return 'Campaign_India_Standard'
    elif country == 'I$NDA':
        return 'Campaign_India_Special'
    elif country == 'Canada':
        return 'Campaign_Canada_Standard'
    elif country == 'CAN':
        return 'Campaign_Canada_Short'
    elif country == 'Australia':
        return 'Campaign_Australia'
    elif country == 'Germany':
        return 'Campaign_Germany'
    elif country == 'France':
        return 'Campaign_France'
    elif country == 'Brazil':
        return 'Campaign_Brazil'
    else:
        return 'Campaign_Other'

